1. Static Array:
```cpp
#include <iostream>
using namespace std;
int main() {
    int arr[3] = {4, 2, 7};
    cout << arr[1]; // Output: 2
}
```
2. Dynamic Array:
```cpp
#include <vector>
using namespace std;
int main() {
    vector<int> arr = {4, 2, 7};
    arr.push_back(1);
    cout << arr[3]; // Output: 1
}
```
3. Multidimensional Array:
```cpp
#include <iostream>
using namespace std;
int main() {
    int arr[2][3] = {{1, 2, 3}, {4, 5, 6}};
    cout << arr[1][2]; // Output: 6
