1. Singly Linked List:
```cpp
#include <iostream>
using namespace std;
struct Node {
    int data;
    Node* next;
    Node(int val) : data(val), next(nullptr) {}
};
int main() {
    Node* head = new Node(1);
    head->next = new Node(2);
    cout << head->data; // Output: 1
}
```
2. Doubly Linked List:
```cpp
#include <iostream>
using namespace std;
struct Node {
    int data;
    Node *prev, *next;
    Node(int val) : data(val), prev(nullptr), next(nullptr) {}
};
int main() {
    Node* n = new Node(1);
    cout << n->data; // Output: 1
}
```
3. Circular Linked List:
```cpp
#include <iostream>
using namespace std;
struct Node {
    int data;
    Node* next;
    Node(int val) : data(val), next(nullptr) {}
};
int main() {
    Node* head = new Node(1);
    head->next = head;
    cout << head->data; // Output: 1
}
```
4. Circular Doubly Linked List:
```cpp
#include <iostream>
using namespace std;
struct Node {
    int data;
    Node *prev, *next;
    Node(int val) : data(val), prev(nullptr), next(nullptr) {}
};
int main() {
    Node* head = new Node(1);
    head->next = head->prev = head;
    cout << head->data; // Output: 1
}
```

